1998 /// Remove empty output blocks from the outlined region.
1999 ///
2000 /// \param BlocksToPrune - Mapping of return values output blocks for the \p
2001 /// Region.
2002 /// \param Region - The OutlinableRegion we are analyzing.
2003 static bool
2004 analyzeAndPruneOutputBlocks(DenseMap<Value *, BasicBlock *> &BlocksToPrune,
2005                             OutlinableRegion &Region) {
2006   bool AllRemoved = true;
2007   Value *RetValueForBB;
2008   BasicBlock *NewBB;
2009   SmallVector<Value *, 4> ToRemove;
2010   // Iterate over the output blocks created in the outlined section.
2011   for (std::pair<Value *, BasicBlock *> &VtoBB : BlocksToPrune) {
2012     RetValueForBB = VtoBB.first;
2013     NewBB = VtoBB.second;
2014   
2015     // If there are no instructions, we remove it from the module, and also
2016     // mark the value for removal from the return value to output block mapping.
2017     if (NewBB->size() == 0) {
2018       NewBB->eraseFromParent();
2019       ToRemove.push_back(RetValueForBB);
2020       continue;
2021     }
2022     
2023     // Mark that we could not remove all the blocks since they were not all
2024     // empty.
2025     AllRemoved = false;
2026   }
2027 
2028   // Remove the return value from the mapping.
2029   for (Value *V : ToRemove)
2030     BlocksToPrune.erase(V);
2031 
2032   // Mark the region as having the no output scheme.
2033   if (AllRemoved)
2034     Region.OutputBlockNum = -1;
2035   
2036   return AllRemoved;
2037 }
