2039 /// For the outlined section, move needed the StoreInsts for the output
2040 /// registers into their own block. Then, determine if there is a duplicate
2041 /// output block already created.
2042 ///
2043 /// \param [in] OG - The OutlinableGroup of regions to be outlined.
2044 /// \param [in] Region - The OutlinableRegion that is being analyzed.
2045 /// \param [in,out] OutputBBs - the blocks that stores for this region will be
2046 /// placed in.
2047 /// \param [in] EndBBs - the final blocks of the extracted function.
2048 /// \param [in] OutputMappings - OutputMappings the mapping of values that have
2049 /// been replaced by a new output value.
2050 /// \param [in,out] OutputStoreBBs - The existing output blocks.
2051 static void alignOutputBlockWithAggFunc(
2052     OutlinableGroup &OG, OutlinableRegion &Region,
2053     DenseMap<Value *, BasicBlock *> &OutputBBs,
2054     DenseMap<Value *, BasicBlock *> &EndBBs,
2055     const DenseMap<Value *, Value *> &OutputMappings,
2056     std::vector<DenseMap<Value *, BasicBlock *>> &OutputStoreBBs) {
2057   // If none of the output blocks have any instructions, this means that we do
2058   // not have to determine if it matches any of the other output schemes, and we
2059   // don't have to do anything else.
2060   if (analyzeAndPruneOutputBlocks(OutputBBs, Region))
2061     return;
2062 
2063   // Determine is there is a duplicate set of blocks.
2064   std::optional<unsigned> MatchingBB =
2065       findDuplicateOutputBlock(OutputBBs, OutputStoreBBs);
2066 
2067   // If there is, we remove the new output blocks.  If it does not,
2068   // we add it to our list of sets of output blocks.
2069   if (MatchingBB) {
2070     LLVM_DEBUG(dbgs() << "Set output block for region in function"
2071                       << Region.ExtractedFunction << " to " << *MatchingBB);
2072 
2073     Region.OutputBlockNum = *MatchingBB;
2074     for (std::pair<Value *, BasicBlock *> &VtoBB : OutputBBs)
2075       VtoBB.second->eraseFromParent();
2076     return;
2077   }
2078 
2079   Region.OutputBlockNum = OutputStoreBBs.size();
2080 
2081   Value *RetValueForBB;
2082   BasicBlock *NewBB;
2083   OutputStoreBBs.push_back(DenseMap<Value *, BasicBlock *>());
2084   for (std::pair<Value *, BasicBlock *> &VtoBB : OutputBBs) {
2085     RetValueForBB = VtoBB.first;
2086     NewBB = VtoBB.second;
2087     DenseMap<Value *, BasicBlock *>::iterator VBBIt =
2088         EndBBs.find(RetValueForBB);
2089     LLVM_DEBUG(dbgs() << "Create output block for region in"
2090                       << Region.ExtractedFunction << " to "
2091                       << *NewBB);
2092     BranchInst::Create(VBBIt->second, NewBB);
2093     OutputStoreBBs.back().insert(std::make_pair(RetValueForBB, NewBB));
2094   }
2095 }
