1914 void replaceConstants(OutlinableRegion &Region) {
1915   OutlinableGroup &Group = *Region.Parent;
1916   Function *OutlinedFunction = Group.OutlinedFunction;
1917 
1918   // Iterate over the constants that need to be elevated into arguments
1919   for (std::pair<unsigned, Constant *> &Const : Region.AggArgToConstant) {
1920     unsigned AggArgIdx = Const.first;
1921     assert(OutlinedFunction && "Overall Function is not defined?");
1922     Constant *CST = Const.second;
1923     Argument *Arg = Group.OutlinedFunction->getArg(AggArgIdx);
1924     LLVM_DEBUG(dbgs() << "Replacing instruction uses of constant " << *CST
1925                       << " in function " << *OutlinedFunction << " with "
1926                       << *Arg << '\n');
1927 
1928     for (auto &BB : *OutlinedFunction) {
1929       for (Instruction &I : BB) {
1930         // We specifically iterate over the direct operands of instructions, to
1931         // avoid replacing constants that appear in `ConstantExpr`s
1932         for (auto &U : I.operands()) {
1933           if (auto *CCandidate = dyn_cast<Constant>(U)) {
1934             if (CCandidate == CST)
1935               U = Arg;
1936           }
1937         }
1938       }
1939     }
1940   }
1941 }
