1943 /// It is possible that there is a basic block that already performs the same
1944 /// stores. This returns a duplicate block, if it exists
1945 ///
1946 /// \param OutputBBs [in] the blocks we are looking for a duplicate of.
1947 /// \param OutputStoreBBs [in] The existing output blocks.
1948 /// \returns an optional value with the number output block if there is a match.
1949 std::optional<unsigned> findDuplicateOutputBlock(
1950     DenseMap<Value *, BasicBlock *> &OutputBBs,
1951     std::vector<DenseMap<Value *, BasicBlock *>> &OutputStoreBBs) {
1952 
1953   bool Mismatch = false;
1954   unsigned MatchingNum = 0;
1955   // We compare the new set output blocks to the other sets of output blocks.
1956   // If they are the same number, and have identical instructions, they are
1957   // considered to be the same.
1958   for (DenseMap<Value *, BasicBlock *> &CompBBs : OutputStoreBBs) {
1959     Mismatch = false;
1960     for (std::pair<Value *, BasicBlock *> &VToB : CompBBs) {
1961       DenseMap<Value *, BasicBlock *>::iterator OutputBBIt =
1962           OutputBBs.find(VToB.first);
1963       if (OutputBBIt == OutputBBs.end()) {
1964         Mismatch = true;
1965         break;
1966       }
1967 
1968       BasicBlock *CompBB = VToB.second;
1969       BasicBlock *OutputBB = OutputBBIt->second;
1970       if (CompBB->size() - 1 != OutputBB->size()) {
1971         Mismatch = true;
1972         break;
1973       }
1974 
1975       BasicBlock::iterator NIt = OutputBB->begin();
1976       for (Instruction &I : *CompBB) {
1977         if (isa<BranchInst>(&I))
1978           continue;
1979 
1980         if (!I.isIdenticalTo(&(*NIt))) {
1981           Mismatch = true;
1982           break;
1983         }
1984 
1985         NIt++;
1986       }
1987     }
1988 
1989     if (!Mismatch)
1990       return MatchingNum;
1991 
1992     MatchingNum++;
1993   }
1994 
1995   return std::nullopt;
1996 }
