2097 /// Takes in a mapping, \p OldMap of ConstantValues to BasicBlocks, sorts keys,
2098 /// before creating a basic block for each \p NewMap, and inserting into the new
2099 /// block. Each BasicBlock is named with the scheme "<basename>_<key_idx>".
2100 ///
2101 /// \param OldMap [in] - The mapping to base the new mapping off of.
2102 /// \param NewMap [out] - The output mapping using the keys of \p OldMap.
2103 /// \param ParentFunc [in] - The function to put the new basic block in.
2104 /// \param BaseName [in] - The start of the BasicBlock names to be appended to
2105 /// by an index value.
2106 static void createAndInsertBasicBlocks(DenseMap<Value *, BasicBlock *> &OldMap,
2107                                        DenseMap<Value *, BasicBlock *> &NewMap,
2108                                        Function *ParentFunc, Twine BaseName) {
2109   unsigned Idx = 0;
2110   std::vector<Value *> SortedKeys;
2111   
2112   getSortedConstantKeys(SortedKeys, OldMap);
2113 
2114   for (Value *RetVal : SortedKeys) {
2115     BasicBlock *NewBB = BasicBlock::Create(
2116         ParentFunc->getContext(), Twine(BaseName) + Twine("_") + Twine(Idx++),
2117         ParentFunc);
2118     NewMap.insert(std::make_pair(RetVal, NewBB));
2119   }
2120 }
