1521 /// evaluating.
1522 /// \returns The found or newly created BasicBlock to contain the needed
1523 /// PHINodes to be used as outputs.
1524 static BasicBlock *findOrCreatePHIBlock(OutlinableGroup &Group, Value *RetVal) {
1525   // Find if a PHIBlock exists for this return value already.  If it is
1526   // the first time we are analyzing this, we will not, so we record it.
1527   auto [PhiBlockForRetVal, Inserted] = Group.PHIBlocks.try_emplace(RetVal);
1528   if (!Inserted)
1529     return PhiBlockForRetVal->second;
1530 
1531   auto ReturnBlockForRetVal = Group.EndBBs.find(RetVal);
1532   assert(ReturnBlockForRetVal != Group.EndBBs.end() &&
1533          "Could not find output value!");
1534   BasicBlock *ReturnBB = ReturnBlockForRetVal->second;
1535 
1536   // If we did not find a block, we create one, and insert it into the
1537   // overall function and record it.
1538   BasicBlock *PHIBlock = BasicBlock::Create(ReturnBB->getContext(), "phi_block",
1539                                             ReturnBB->getParent());
1540   PhiBlockForRetVal->second = PHIBlock;
1541 
1542   // We find the predecessors of the return block in the newly created outlined
1543   // function in order to point them to the new PHIBlock rather than the already
1544   // existing return block.
