1550   // return block to the newly created PHIBlock.
1551   for (BranchInst *BI : BranchesToChange)
1552     for (unsigned Succ = 0, End = BI->getNumSuccessors(); Succ < End; Succ++) {
1553       if (BI->getSuccessor(Succ) != ReturnBB)
1554         continue;
1555       BI->setSuccessor(Succ, PHIBlock);
