1009 /// Check if the \p V has any uses outside of the region other than \p PN.
1010 ///
1011 /// \param V [in] - The value to check.
1012 /// \param PHILoc [in] - The location in the PHINode of \p V.
1013 /// \param PN [in] - The PHINode using \p V.
1014 /// \param Exits [in] - The potential blocks we exit to from the outlined
1015 /// region.
1016 /// \param BlocksInRegion [in] - The basic blocks contained in the region.
1017 /// \returns true if \p V has any use soutside its region other than \p PN.
1018 static bool outputHasNonPHI(Value *V, unsigned PHILoc, PHINode &PN,
1019                             SmallPtrSet<BasicBlock *, 1> &Exits,
1020                             DenseSet<BasicBlock *> &BlocksInRegion) {
1021   // We check to see if the value is used by the PHINode from some other
1022   // predecessor not included in the region.  If it is, we make sure
1023   // to keep it as an output.
1024   if (any_of(llvm::seq<unsigned>(0, PN.getNumIncomingValues()),
1025              [PHILoc, &PN, V, &BlocksInRegion](unsigned Idx) {
1026                return (Idx != PHILoc && V == PN.getIncomingValue(Idx) &&
1027                        !BlocksInRegion.contains(PN.getIncomingBlock(Idx)));
1028              }))
1029     return true;
1030 
1031   // Check if the value is used by any other instructions outside the region.
1032   return any_of(V->users(), [&Exits, &BlocksInRegion](User *U) {
1033     Instruction *I = dyn_cast<Instruction>(U);
1034     if (!I)
1035       return false;
1036 
1037     // If the use of the item is inside the region, we skip it.  Uses
1038     // inside the region give us useful information about how the item could be
1039     // used as an output.
1040     BasicBlock *Parent = I->getParent();
1041     if (BlocksInRegion.contains(Parent))
1042       return false;
1043 
1044     // If it's not a PHINode then we definitely know the use matters.  This
1045     // output value will not completely combined with another item in a PHINode
1046     // as it is directly reference by another non-phi instruction
1047     if (!isa<PHINode>(I))
1048       return true;
1049 
1050     // If we have a PHINode outside one of the exit locations, then it
1051     // can be considered an outside use as well.  If there is a PHINode
1052     // contained in the Exit where this values use matters, it will be
1053     // caught when we analyze that PHINode.
1054     if (!Exits.contains(Parent))
1055       return true;
1056 
1057     return false;
1058   });
