1061 /// Test whether \p CurrentExitFromRegion contains any PhiNodes that should be
1062 /// considered outputs. A PHINodes is an output when more than one incoming
1063 /// value has been marked by the CodeExtractor as an output.
1064 ///
1065 /// \param CurrentExitFromRegion [in] - The block to analyze.
1066 /// \param PotentialExitsFromRegion [in] - The potential exit blocks from the
1067 /// region.
1068 /// \param RegionBlocks [in] - The basic blocks in the region.
1069 /// \param Outputs [in, out] - The existing outputs for the region, we may add
1070 /// PHINodes to this as we find that they replace output values.
1071 /// \param OutputsReplacedByPHINode [out] - A set containing outputs that are
1072 /// totally replaced  by a PHINode.
1073 /// \param OutputsWithNonPhiUses [out] - A set containing outputs that are used
1074 /// in PHINodes, but have other uses, and should still be considered outputs.
1075 static void analyzeExitPHIsForOutputUses(
1076     BasicBlock *CurrentExitFromRegion,
1077     SmallPtrSet<BasicBlock *, 1> &PotentialExitsFromRegion,
1078     DenseSet<BasicBlock *> &RegionBlocks, SetVector<Value *> &Outputs,
1079     DenseSet<Value *> &OutputsReplacedByPHINode,
1080     DenseSet<Value *> &OutputsWithNonPhiUses) {
1081   for (PHINode &PN : CurrentExitFromRegion->phis()) {
1082     // Find all incoming values from the outlining region.
1083     SmallVector<unsigned, 2> IncomingVals;
1084     for (unsigned I = 0, E = PN.getNumIncomingValues(); I < E; ++I)
1085       if (RegionBlocks.contains(PN.getIncomingBlock(I)))
1086         IncomingVals.push_back(I);
1087 
1088     // Do not process PHI if there are no predecessors from region.
1089     unsigned NumIncomingVals = IncomingVals.size();
1090     if (NumIncomingVals == 0)
1091       continue;
1092 
1093     // If there is one predecessor, we mark it as a value that needs to be kept
1094     // as an output.
1095     if (NumIncomingVals == 1) {
1096       Value *V = PN.getIncomingValue(*IncomingVals.begin());
1097       OutputsWithNonPhiUses.insert(V);
1098       OutputsReplacedByPHINode.erase(V);
1099       continue;
1100     }
1101 
1102     // This PHINode will be used as an output value, so we add it to our list.
1103     Outputs.insert(&PN);
1104 
1105     // Not all of the incoming values should be ignored as other inputs and
1106     // outputs may have uses in outlined region.  If they have other uses
1107     // outside of the single PHINode we should not skip over it.
1108     for (unsigned Idx : IncomingVals) {
1109       Value *V = PN.getIncomingValue(Idx);
1110       if (!isa<Constant>(V) &&
1111           outputHasNonPHI(V, Idx, PN, PotentialExitsFromRegion, RegionBlocks)) {
1112         OutputsWithNonPhiUses.insert(V);
1113         OutputsReplacedByPHINode.erase(V);
1114         continue;
1115       }
1116       if (!OutputsWithNonPhiUses.contains(V))
1117         OutputsReplacedByPHINode.insert(V);
1118     }
1119   }
